"""Workflow Tools — 워크플로우 관련 도구를 ToolSpec으로 생성."""

from __future__ import annotations

import logging
from typing import Any

from mantis.tools.decorator import tool, ToolSpec
from mantis.tools.registry import ToolRegistry
from mantis.workflow.models import WorkflowDef, WorkflowStep, WorkflowEdge
from mantis.workflow.store import WorkflowStore
from mantis.workflow.generator import WorkflowGenerator

logger = logging.getLogger(__name__)


def make_workflow_tools(
    store: WorkflowStore,
    registry: ToolRegistry,
    generator: WorkflowGenerator | None = None,
) -> list[ToolSpec]:
    """워크플로우 관련 도구를 생성하여 반환.

    - generate_workflow: LLM으로 워크플로우 자동 생성 (generator 있을 때만)
    - create_workflow: 수동으로 워크플로우 생성
    - run_workflow: 워크플로우 실행 (FlowState 기반)
    - list_workflows: 저장된 워크플로우 목록 조회
    """

    @tool(
        name="generate_workflow",
        description=(
            "자연어 설명으로부터 워크플로우를 자동 생성한다. "
            "사용 가능한 도구를 참고하여 LLM이 단계별 워크플로우를 설계한다."
        ),
        parameters={
            "description": {
                "type": "string",
                "description": "생성할 워크플로우에 대한 자연어 설명",
            },
        },
    )
    async def generate_workflow(description: str) -> dict:
        if generator is None:
            return {"status": "error", "error": "워크플로우 생성기가 설정되지 않음"}
        try:
            workflow = await generator.generate(description)
            return {
                "status": "success",
                "name": workflow.name,
                "description": workflow.description,
                "steps_count": len(workflow.steps),
                "steps": [
                    {"id": s.id, "type": s.type, "tool": s.tool}
                    for s in workflow.steps
                ],
            }
        except Exception as e:
            logger.exception("워크플로우 생성 실패")
            return {"status": "error", "error": str(e)}

    @tool(
        name="create_workflow",
        description=(
            "워크플로우를 수동으로 생성한다. "
            "이름, 설명, 단계 목록을 직접 지정하여 저장한다."
        ),
        parameters={
            "name": {
                "type": "string",
                "description": "워크플로우 이름",
            },
            "description": {
                "type": "string",
                "description": "워크플로우 설명",
            },
            "steps": {
                "type": "array",
                "description": "단계 목록. 각 단계는 id, type 등을 포함하는 dict",
                "items": {"type": "object"},
            },
            "edges": {
                "type": "array",
                "description": "단계 간 데이터 연결 (선택)",
                "items": {"type": "object"},
                "optional": True,
            },
        },
    )
    async def create_workflow(
        name: str,
        description: str,
        steps: list[dict[str, Any]],
        edges: list[dict[str, Any]] | None = None,
    ) -> dict:
        try:
            workflow_steps = [
                WorkflowStep(
                    id=s["id"],
                    type=s.get("type", "tool"),
                    tool=s.get("tool"),
                    args=s.get("args"),
                    args_from=s.get("args_from"),
                    condition=s.get("condition"),
                    then_step=s.get("then_step"),
                    else_step=s.get("else_step"),
                    prompt=s.get("prompt"),
                    tools=s.get("tools"),
                    parallel_steps=s.get("parallel_steps"),
                )
                for s in steps
            ]

            workflow_edges: list[WorkflowEdge] | None = None
            if edges:
                workflow_edges = [
                    WorkflowEdge(
                        source_step=e["source_step"],
                        source_key=e["source_key"],
                        target_step=e["target_step"],
                        target_key=e["target_key"],
                    )
                    for e in edges
                ]

            workflow_def = WorkflowDef(
                name=name,
                description=description,
                steps=workflow_steps,
                edges=workflow_edges,
            )
            store.save(name, workflow_def)

            return {
                "status": "success",
                "name": name,
                "steps_count": len(workflow_steps),
            }
        except Exception as e:
            logger.exception("워크플로우 생성 실패")
            return {"status": "error", "error": str(e)}

    @tool(
        name="run_workflow",
        description=(
            "저장된 워크플로우를 실행한다. "
            "워크플로우 이름과 입력 데이터를 지정하여 단계별로 실행한다."
        ),
        parameters={
            "workflow_name": {
                "type": "string",
                "description": "실행할 워크플로우 이름",
            },
            "input_data": {
                "type": "object",
                "description": "워크플로우에 전달할 입력 데이터 (선택)",
                "optional": True,
            },
        },
    )
    async def run_workflow(
        workflow_name: str,
        input_data: dict[str, Any] | None = None,
    ) -> dict:
        try:
            workflow = store.get(workflow_name)
            if workflow is None:
                return {
                    "status": "error",
                    "error": f"워크플로우 '{workflow_name}'을 찾을 수 없음",
                }

            from mantis.executor.flow import flow_from_workflow
            flow = flow_from_workflow(workflow)
            if input_data:
                flow.step_results["input"] = input_data

            while not flow.is_done:
                step = flow.current_step()

                if step.type == "tool":
                    args = flow.resolve_args(step)
                    result = await registry.execute(
                        {"name": step.tool, "arguments": args},
                    )
                    if "error" in result:
                        flow.step_results[step.id] = {"error": result["error"]}
                    else:
                        flow.step_results[step.id] = result.get("result", result)
                    flow.advance()

                elif step.type == "condition":
                    taken = flow.evaluate_condition(step.condition or "")
                    target = step.then_step if taken else step.else_step
                    skipped = step.else_step if taken else step.then_step
                    if skipped:
                        flow.skip(skipped)
                    flow.step_results[step.id] = {
                        "condition": step.condition,
                        "result": taken,
                        "next": target,
                    }
                    flow.advance(target)

                elif step.type == "parallel":
                    import asyncio
                    tasks = []
                    step_map = {s.id: s for s in flow.steps}
                    for ps_id in (step.parallel_steps or []):
                        ps = step_map.get(ps_id)
                        if ps and ps.type == "tool":
                            args = flow.resolve_args(ps)
                            tasks.append(registry.execute(
                                {"name": ps.tool, "arguments": args},
                            ))
                    results = await asyncio.gather(*tasks, return_exceptions=True)
                    parallel_results = {}
                    for ps_id, res in zip(step.parallel_steps or [], results):
                        if isinstance(res, Exception):
                            parallel_results[ps_id] = {"error": str(res)}
                        elif isinstance(res, dict):
                            parallel_results[ps_id] = res.get("result", res)
                        else:
                            parallel_results[ps_id] = res
                    flow.step_results[step.id] = parallel_results
                    flow.advance()

                else:
                    flow.step_results[step.id] = {"error": f"unsupported type: {step.type}"}
                    flow.advance()

            return {"status": "success", "workflow": workflow_name, "result": flow.step_results}
        except Exception as e:
            logger.exception("워크플로우 실행 실패")
            return {"status": "error", "error": str(e)}

    @tool(
        name="list_workflows",
        description="저장된 모든 워크플로우 목록을 조회한다.",
        parameters={},
    )
    async def list_workflows() -> dict:
        try:
            workflows = store.list_all()
            return {
                "status": "success",
                "count": len(workflows),
                "workflows": [
                    {
                        "name": w.name,
                        "description": w.description,
                        "steps_count": len(w.steps),
                    }
                    for w in workflows
                ],
            }
        except Exception as e:
            logger.exception("워크플로우 목록 조회 실패")
            return {"status": "error", "error": str(e)}

    return [
        generate_workflow._tool_spec,
        create_workflow._tool_spec,
        run_workflow._tool_spec,
        list_workflows._tool_spec,
    ]
